import importlib
import time
import statistics
import functools
import logging
from typing import Dict, List, Optional

logger = logging.getLogger(__name__)

class DependencyError(Exception):
    pass

class QueryExecutionError(Exception):
    pass

class PerformanceMetrics:
    def __init__(self):
        self.query_count: int = 0
        self.success_count: int = 0
        self.error_count: int = 0
        self.response_times: List[float] = []
        self.error_history: List[Dict] = []

    def record_query(self, success: bool, response_time: float, error_info: Optional[Dict] = None):
        self.query_count += 1
        if success:
            self.success_count += 1
            self.response_times.append(response_time)
        else:
            self.error_count += 1
            if error_info:
                self.error_history.append(error_info)

    @property
    def success_rate(self) -> float:
        return self.success_count / self.query_count if self.query_count > 0 else 0.0

    @property
    def avg_response_time(self) -> float:
        return statistics.mean(self.response_times) if self.response_times else 0.0

    def get_summary(self) -> Dict:
        return {
            'success_rate': self.success_rate,
            'avg_response_time': self.avg_response_time,
            'total_queries': self.query_count,
            'error_count': self.error_count
        }

class ScoutBase:
    REQUIRED_PACKAGES = {
        'datetime': {'min_version': '3.0'},
        'os': {'required': True},
        'langchain': {'min_version': '0.1.0'},
        'numpy': {'optional': True}
    }

    def __init__(self):
        self.metrics = PerformanceMetrics()
        self.verify_dependencies()

    @classmethod
    def verify_dependencies(cls) -> None:
        missing = []
        outdated = []
        for package, config in cls.REQUIRED_PACKAGES.items():
            try:
                if config.get('required', True):
                    module = importlib.import_module(package)
                    if 'min_version' in config:
                        if getattr(module, '__version__', '0.0.0') < config['min_version']:
                            outdated.append(package)
            except ImportError:
                if not config.get('optional', False):
                    missing.append(package)

        if missing or outdated:
            raise DependencyError(f'Dependencies issue: Missing: {missing}, Outdated: {outdated}')

    def safe_execute(self, func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            start_time = time.time()
            try:
                result = func(*args, **kwargs)
                execution_time = time.time() - start_time
                self.metrics.record_query(True, execution_time)
                return result
            except Exception as e:
                execution_time = time.time() - start_time
                error_info = {
                    'error_type': type(e).__name__,
                    'error_message': str(e),
                    'timestamp': time.time()
                }
                self.metrics.record_query(False, execution_time, error_info)
                logger.error(f'Query execution failed: {str(e)}')
                raise QueryExecutionError(f'Failed to execute query: {str(e)}') from e
        return wrapper

