from typing import Dict, Any, Optional
import time
import functools
import logging
from dataclasses import dataclass

@dataclass
class DependencyConfig:
    min_version: str
    required: bool

class QueryExecutionError(Exception):
    pass

class QueryPerformanceMonitor:
    def __init__(self):
        self.metrics = {
            'query_count': 0,
            'success_count': 0,
            'error_count': 0,
            'response_times': [],
            'error_distribution': {},
            'query_complexity': []
        }
        self.logger = logging.getLogger('scout_performance')

    def record_query(self, success: bool, execution_time: float, error: Optional[Exception] = None) -> None:
        self.metrics['query_count'] += 1
        if success:
            self.metrics['success_count'] += 1
            self.metrics['response_times'].append(execution_time)
        else:
            self.metrics['error_count'] += 1
            error_type = type(error).__name__
            self.metrics['error_distribution'][error_type] = \
                self.metrics['error_distribution'].get(error_type, 0) + 1

    def get_success_rate(self) -> float:
        if self.metrics['query_count'] == 0:
            return 0.0
        return self.metrics['success_count'] / self.metrics['query_count']

    def get_average_response_time(self) -> float:
        if not self.metrics['response_times']:
            return 0.0
        return sum(self.metrics['response_times']) / len(self.metrics['response_times'])

class ScoutCrewCore:
    DEPENDENCIES = {
        'langchain': DependencyConfig(min_version='0.1.0', required=True),
        'numpy': DependencyConfig(min_version='1.21.0', required=False),
        'pandas': DependencyConfig(min_version='1.3.0', required=True)
    }

    def __init__(self):
        self.performance_monitor = QueryPerformanceMonitor()
        self.logger = logging.getLogger('scout_core')
        self._verify_dependencies()

    def _verify_dependencies(self) -> None:
        import pkg_resources
        for package, config in self.DEPENDENCIES.items():
            try:
                version = pkg_resources.get_distribution(package).version
                if pkg_resources.parse_version(version) < pkg_resources.parse_version(config.min_version):
                    msg = f'{package} version {version} is lower than required {config.min_version}'
                    if config.required:
                        raise ValueError(msg)
                    self.logger.warning(msg)
            except pkg_resources.DistributionNotFound:
                if config.required:
                    raise ValueError(f'Required package {package} is not installed')
                self.logger.warning(f'Optional package {package} is not installed')

    def safe_execute_query(self, query_func):
        @functools.wraps(query_func)
        def wrapper(*args, **kwargs):
            start_time = time.time()
            retry_count = 0
            max_retries = 3
            last_error = None

            while retry_count < max_retries:
                try:
                    result = query_func(*args, **kwargs)
                    execution_time = time.time() - start_time
                    self.performance_monitor.record_query(
                        success=True,
                        execution_time=execution_time
                    )
                    return result
                except Exception as e:
                    last_error = e
                    retry_count += 1
                    self.logger.warning(
                        f'Query execution failed (attempt {retry_count}/{max_retries}): {str(e)}'
                    )
                    if retry_count < max_retries:
                        time.sleep(retry_count * 2)  # Exponential backoff

            execution_time = time.time() - start_time
            self.performance_monitor.record_query(
                success=False,
                execution_time=execution_time,
                error=last_error
            )
            raise QueryExecutionError(f'Max retries exceeded: {str(last_error)}')

        return wrapper

    def get_performance_metrics(self) -> Dict[str, Any]:
        return {
            'success_rate': self.performance_monitor.get_success_rate(),
            'avg_response_time': self.performance_monitor.get_average_response_time(),
            'error_distribution': self.performance_monitor.metrics['error_distribution']
        }

