from typing import Dict, Any, Optional
import time
import numpy as np
from dataclasses import dataclass

@dataclass
class PerformanceMetrics:
    query_count: int = 0
    success_count: int = 0
    total_response_time: float = 0.0
    error_count: int = 0
    last_sentiment_scores: list = None

class ScoutCrew:
    def __init__(self):
        self.metrics = PerformanceMetrics()
        self.metrics.last_sentiment_scores = []
        self.error_recovery_attempts = 0
        self.MAX_RECOVERY_ATTEMPTS = 3

    def analyze_market(self, market_data: Dict[str, Any]) -> Dict[str, Any]:
        start_time = time.time()
        try:
            # 感情スコアの平滑化処理
            sentiment_score = self._calculate_smoothed_sentiment(market_data)

            # セクター別リスク制限の動的調整
            risk_limits = self._adjust_risk_limits(market_data)

            # 市場分析の実行
            analysis_result = self._execute_analysis(market_data, sentiment_score, risk_limits)

            # パフォーマンスメトリクスの更新
            self._update_metrics(True, time.time() - start_time)

            return analysis_result

        except Exception as e:
            self._update_metrics(False, time.time() - start_time)
            return self._handle_error(e, market_data)

    def _calculate_smoothed_sentiment(self, market_data: Dict[str, Any]) -> float:
        current_sentiment = market_data.get('sentiment', 0.5)
        self.metrics.last_sentiment_scores.append(current_sentiment)

        # 直近5回の感情スコアで指数移動平均を計算
        if len(self.metrics.last_sentiment_scores) > 5:
            self.metrics.last_sentiment_scores.pop(0)

        weights = np.exp(np.linspace(-1., 0., len(self.metrics.last_sentiment_scores)))
        weights /= weights.sum()

        return np.average(self.metrics.last_sentiment_scores, weights=weights)

    def _adjust_risk_limits(self, market_data: Dict[str, Any]) -> Dict[str, float]:
        base_limits = market_data.get('sector_limits', {})
        volatility = market_data.get('market_volatility', 1.0)

        # ボラティリティに基づくリスク制限の動的調整
        return {sector: limit * (1.0 / volatility) for sector, limit in base_limits.items()}

    def _update_metrics(self, success: bool, response_time: float) -> None:
        self.metrics.query_count += 1
        if success:
            self.metrics.success_count += 1
            self.metrics.total_response_time += response_time
        else:
            self.metrics.error_count += 1

    def _handle_error(self, error: Exception, market_data: Dict[str, Any]) -> Dict[str, Any]:
        if self.error_recovery_attempts < self.MAX_RECOVERY_ATTEMPTS:
            self.error_recovery_attempts += 1
            # 簡略化されたフォールバック分析を実行
            return self._execute_fallback_analysis(market_data)
        else:
            raise RuntimeError(f'Maximum recovery attempts reached: {str(error)}')

    def get_performance_stats(self) -> Dict[str, float]:
        return {
            'success_rate': self.metrics.success_count / max(1, self.metrics.query_count),
            'avg_response_time': self.metrics.total_response_time / max(1, self.metrics.success_count),
            'error_rate': self.metrics.error_count / max(1, self.metrics.query_count)
        }

