import asyncio
from typing import Dict, Any
from datetime import datetime, timedelta

class AdaptiveCache:
    def __init__(self, max_size: int = 1000):
        self.cache: Dict[str, Any] = {}
        self.ttl: Dict[str, datetime] = {}
        self.max_size = max_size
        self.hit_count = 0
        self.miss_count = 0

    def get(self, key: str) -> Any:
        if key in self.cache and datetime.now() < self.ttl[key]:
            self.hit_count += 1
            return self.cache[key]
        self.miss_count += 1
        return None

    def set(self, key: str, value: Any, ttl_minutes: int = 30):
        if len(self.cache) >= self.max_size:
            self._evict_oldest()
        self.cache[key] = value
        self.ttl[key] = datetime.now() + timedelta(minutes=ttl_minutes)

    def _evict_oldest(self):
        oldest_key = min(self.ttl.items(), key=lambda x: x[1])[0]
        del self.cache[oldest_key]
        del self.ttl[oldest_key]

class KalmanFilter:
    def __init__(self, process_variance=1e-5, measurement_variance=1e-2):
        self.process_variance = process_variance
        self.measurement_variance = measurement_variance
        self.estimate = 0.0
        self.estimate_error = 1.0

    def update(self, measurement):
        prediction_error = self.estimate_error + self.process_variance
        kalman_gain = prediction_error / (prediction_error + self.measurement_variance)
        self.estimate = self.estimate + kalman_gain * (measurement - self.estimate)
        self.estimate_error = (1 - kalman_gain) * prediction_error
        return self.estimate

