        return np.std(market_data['price_history']) / np.mean(market_data['price_history'])

    async def get_risk_limit(self, sector: str) -> float:
        base_limit = self.sector_risk_limits[sector]
        market_conditions = await self._get_market_conditions(sector)
        return base_limit * (1 + market_conditions['risk_adjustment'])

    async def _compute_raw_sentiment(self, market_data: dict) -> float:
        tasks = [
            self._analyze_price_action(market_data),
            self._analyze_volume(market_data),
