    async def _analyze_news_sentiment(self, market_data: dict) -> float:
        try:
            async with aiohttp.ClientSession() as session:
                async with session.get(f"/api/news/{market_data['symbol']}") as response:
                    news_data = await response.json()
                    return self._process_news_sentiment(news_data)
        except Exception as e:
