from datetime import datetime, timedelta
from typing import Dict, Any, Optional
from tenacity import retry, stop_after_attempt, wait_exponential

class EnhancedAPIManager:
    def __init__(self):
        self.providers = {
            'anthropic': {'priority': 1, 'api_key': None, 'health': True},
            'openai': {'priority': 2, 'api_key': None, 'health': True},
            'openrouter': {'priority': 3, 'api_key': None, 'health': True}
        }
        self.cache_manager = CacheManager()

    def get_provider_chain(self):
        return sorted(
            [(k, v) for k, v in self.providers.items() if v['health']],
            key=lambda x: x[1]['priority']
        )

class CacheManager:
    def __init__(self, ttl_hours: int = 1):
        self.cache = {}
        self.ttl = timedelta(hours=ttl_hours)

    def get_cached_data(self, key: str) -> Optional[Dict]:
        if key in self.cache:
            cache_entry = self.cache[key]
            if datetime.now() - cache_entry['timestamp'] < self.ttl:
                return cache_entry['data']
        return None

    def set_cached_data(self, key: str, data: Dict):
        self.cache[key] = {
            'data': data,
            'timestamp': datetime.now()
        }

class ScoutAgent:
    def __init__(self):
        self.api_manager = EnhancedAPIManager()
        self.error_counter = {}

    @retry(stop=stop_after_attempt(3), wait=wait_exponential(multiplier=1, min=4, max=10))
    async def execute_query(self, query: str) -> Dict[str, Any]:
        cache_key = f'query_{hash(query)}'
        cached_result = self.api_manager.cache_manager.get_cached_data(cache_key)

        if cached_result:
            return cached_result

        for provider, config in self.api_manager.get_provider_chain():
            try:
                result = await self._query_provider(provider, query)
                if self._validate_response(result):
                    self.api_manager.cache_manager.set_cached_data(cache_key, result)
                    return result
            except Exception as e:
                self._handle_provider_error(provider, e)
                continue

        raise Exception('All providers failed')

    def _validate_response(self, response: Dict) -> bool:
        required_fields = ['sentiment', 'relevance_score', 'strategic_value']
        return all(field in response for field in required_fields) and \
               response['relevance_score'] >= 0.6

    def _handle_provider_error(self, provider: str, error: Exception):
        self.error_counter[provider] = self.error_counter.get(provider, 0) + 1
        if self.error_counter[provider] >= 3:
            self.api_manager.providers[provider]['health'] = False
